// src/api/auth.js
import axios from "axios";

const API_URL = "https://prasa-app-yde3.onrender.com/api/app";
// For local testing:
// const API_URL = "http://localhost:10000/api/app";


// LOGIN
export const loginUser = (empId, password) =>
  axios.post(API_URL, { action: "login", empId, password });


// DASHBOARD SUMMARY
export const getDashboard = (empId) =>
  axios.post(API_URL, { action: "dashboard", empId });


// ADD TRAVEL
export const addTravel = (payload) =>
  axios.post(API_URL, { action: "addTravel", ...payload });


// ADD TICKET
export const addTicket = (payload) =>
  axios.post(API_URL, { action: "addTicket", ...payload });


// HISTORY
export const getHistory = (empId) =>
  axios.post(API_URL, { action: "history", empId });


// GRAPH DATA
export const getGraphData = (empId) =>
  axios.post(API_URL, { action: "graph", empId });


// UPLOAD BILL (File + DB)
export const uploadBill = (payload) =>
  axios.post(API_URL, { action: "uploadBill", ...payload });


// GENERATE MONTHLY PDF REPORT
export const generateReport = (payload) =>
  axios.post(API_URL, { action: "generateReport", ...payload });
